#include <iostream>
#include <string>

class Teacher
{
    std::string m_name;

public:
    Teacher(std::string name)
        : m_name{ name }
    {
    }

    const std::string& getName() const { return m_name; }
};

class Department
{
    std::string m_name;
    const Teacher& m_lead;

public:
    Department(std::string name, const Teacher& lead)
        : m_name{ name }
        , m_lead{ lead }
    {
    }

    void print() const
    {
        std::cout << m_name << ": " << m_lead.getName() << '\n';
    }
};

int main()
{
    std::string teacherName{};
    std::string deptName{};
    std::cin >> teacherName >> deptName;

    Teacher t{ teacherName };
    Department d{ deptName, t };
    d.print();

    return 0;
}

